Let $(S_0, v_0, \lambda_0)$ be a simple eigenpair with $\langle v_0, v_0\rangle = 1$. Then there are an open set $W \subseteq \operatorname{End}(V)$ containing $S_0$ and maps $\mathcal{V} : W \to V$, $\Lambda : W \to \mathbb{R}$ such that
\begin{enumerate}
  \item $\mathcal{V}(S_0) = v_0$ and $\Lambda(S_0) = \lambda_0$;
  \item $S\,\mathcal{V}(S) = \Lambda(S)\,\mathcal{V}(S)$ and $\langle v_0, \mathcal{V}(S)\rangle = 1$ for every $S \in W$;
  \item $\mathcal{V}$ and $\Lambda$ are continuous on $W$;
  \item $\mathcal{V}$ and $\Lambda$ are smooth at every $S \in W$ for which $(S, \mathcal{V}(S), \Lambda(S))$ is again a simple eigenpair.
\end{enumerate}

Let $(M, g)$ be a Riemannian manifold.
\begin{enumerate}
\item[(a)] If $M$ is isotropic at one point and it is homogeneous, then it is isotropic.
\item[(b)] If $M$ is frame-homogeneous, then it is homogeneous and isotropic.
\end{enumerate}

Let $n$ be an integer greater than 1. For each fixed $R > 0$, the following Riemannian manifolds are all mutually isometric.

\begin{enumerate}
\item[(a)] (HYPERBOLOID MODEL) $\mathbb{H}^n(R)$ is the submanifold of Minkowski space $\mathbb{R}^{n,1}$ defined in standard coordinates $(\xi^1, \ldots, \xi^n, \tau)$ as the ``upper sheet'' $\{\tau > 0\}$ of the two-sheeted hyperboloid $(\xi^1)^2 + \cdots + (\xi^n)^2 - \tau^2 = -R^2$, with the induced metric
\[
\bar{g}_R = \iota^* \bar{g},
\]
where $\iota: \mathbb{H}^n(R) \to \mathbb{R}^{n,1}$ is inclusion, and $\bar{g} = \bar{g}^{(n,1)}$ is the Minkowski metric:
\begin{equation}
\bar{g} = (d\xi^1)^2 + \cdots + (d\xi^n)^2 - (d\tau)^2. \tag{3.8}
\end{equation}

\item[(b)] (BELTRAMI--KLEIN MODEL) $\mathbb{K}^n(R)$ is the ball of radius $R$ centered at the origin in $\mathbb{R}^n$, with the metric given in coordinates $(w^1, \ldots, w^n)$ by
\begin{equation}
\bar{g}_R = R^2 \frac{(dw^1)^2 + \cdots + (dw^n)^2}{R^2 - |w|^2} + R^2 \frac{(w^1 dw^1 + \cdots + w^n dw^n)^2}{(R^2 - |w|^2)^2}. \tag{3.9}
\end{equation}

\item[(c)] (POINCARÉ BALL MODEL) $\mathbb{B}^n(R)$ is the ball of radius $R$ centered at the origin in $\mathbb{R}^n$, with the metric given in coordinates $(u^1, \ldots, u^n)$ by
\[
\bar{g}_R = 4R^4 \frac{(du^1)^2 + \cdots + (du^n)^2}{(R^2 - |u|^2)^2}.
\]

\item[(d)] (POINCARÉ HALF-SPACE MODEL) $\mathbb{U}^n(R)$ is the upper half-space in $\mathbb{R}^n$ defined in coordinates $(x^1, \ldots, x^{n-1}, y)$ by $\mathbb{U}^n(R) = \{(x, y) : y > 0\}$, endowed with the metric
\[
\bar{g}_R = R^2 \frac{(dx^1)^2 + \cdots + (dx^{n-1})^2 + dy^2}{y^2}.
\]
\end{enumerate}

Let $G$ be a Lie group and $\mathfrak{g}$ its Lie algebra. Suppose $g$ is a left-invariant Riemannian metric on $G$, and let $\langle \cdot, \cdot \rangle$ denote the corresponding inner product on $\mathfrak{g}$ as in Lemma 3.10. Then $g$ is bi-invariant if and only if $\langle \cdot, \cdot \rangle$ is invariant under the action of $\operatorname{Ad}(G) \subseteq \operatorname{GL}(\mathfrak{g})$, in the sense that $\langle \operatorname{Ad}(\varphi)X, \operatorname{Ad}(\varphi)Y \rangle = \langle X, Y \rangle$ for all $X, Y \in \mathfrak{g}$ and $\varphi \in G$.

\textbf{Proof.} We begin the proof with some preliminary computations. Suppose $g$ is left-invariant and $\langle \cdot, \cdot \rangle$ is the associated inner product on $\mathfrak{g}$. Let $\varphi \in G$ be arbitrary, and note that $C_\varphi$ is the composition of left multiplication by $\varphi$ followed by right multiplication by $\varphi^{-1}$. Thus for every $X \in \mathfrak{g}$, left-invariance implies $(R_{\varphi^{-1}})_* X = (R_{\varphi^{-1}})_* (L_\varphi)_* X = (C_\varphi)_* X = \operatorname{Ad}(\varphi)X$. Therefore, for all $\psi \in G$ and $X, Y \in \mathfrak{g}$, we have
\begin{align*}
((R_{\varphi^{-1}})^* g)_\psi (X_\psi, Y_\psi) &= g_{\psi\varphi^{-1}} (((R_{\varphi^{-1}})_* X)_{\psi\varphi^{-1}}, ((R_{\varphi^{-1}})_* Y)_{\psi\varphi^{-1}}) \\
&= g_{\psi\varphi^{-1}} ((\operatorname{Ad}(\varphi)X)_{\psi\varphi^{-1}}, (\operatorname{Ad}(\varphi)Y)_{\psi\varphi^{-1}}) \\
&= \langle \operatorname{Ad}(\varphi)X, \operatorname{Ad}(\varphi)Y \rangle.
\end{align*}

Now assume that $\langle \cdot, \cdot \rangle$ is invariant under $\operatorname{Ad}(G)$. Then the expression on the last line above is equal to $\langle X, Y \rangle = g_\psi(X_\psi, Y_\psi)$, which shows that $(R_{\varphi^{-1}})^* g = g$. Since this is true for all $\varphi \in G$, it follows that $g$ is bi-invariant.

Conversely, assuming that $g$ is bi-invariant, we have $(R_{\varphi^{-1}})^* g = g$ for each $\varphi \in G$, so the above computation yields
\begin{align*}
\langle X, Y \rangle = g_\psi(X_\psi, Y_\psi) = ((R_{\varphi^{-1}})^* g)_\psi(X_\psi, Y_\psi) = \langle \operatorname{Ad}(\varphi)X, \operatorname{Ad}(\varphi)Y \rangle,
\end{align*}
which shows that $\langle \cdot, \cdot \rangle$ is $\operatorname{Ad}(G)$-invariant. \quad $\square$

Suppose $
abla$ is a connection in a smooth vector bundle $E 	o M$. For every open subset $U \subseteq M$, there is a unique connection $
abla^U$ on the restricted bundle $E|_U$ that satisfies the following relation for every $X \in \mathfrak{X}(M)$ and $Y \in \Gamma(E)$:
 egin{equation}

abla^U_{(X|_U)}(Y|_U) = (
abla_X Y)|_U. 	ag{4.6}
\end{equation}

Let $M$ be a smooth manifold with or without boundary, and let $\nabla$ be a connection in $TM$. Suppose $(E_i)$ is a smooth local frame over an open subset $U \subseteq M$, and let $\{\Gamma^k_{ij}\}$ be the connection coefficients of $\nabla$ with respect to this frame. For smooth vector fields $X,Y \in \mathfrak{X}(U)$, written in terms of the frame as $X = X^i E_i$, $Y = Y^j E_j$, one has
\begin{equation}
\nabla_X Y = \left(X(Y^k) + X^i Y^j \Gamma^k_{ij}\right) E_k. \tag{4.9}
\end{equation}

Let $M$ be a smooth manifold with or without boundary and let $\nabla$ be a connection in $TM$. For every $F \in \Gamma(T^{(k,\ell)}TM)$, the map
\[
\nabla F: \underbrace{\Omega^1(M) \times \cdots \times \Omega^1(M)}_{k \text{ copies}} \times \underbrace{\mathfrak{X}(M) \times \cdots \times \mathfrak{X}(M)}_{\ell+1 \text{ copies}} \to C^\infty(M)
\]
given by
\begin{equation}
(\nabla F)(\omega^1, \ldots, \omega^k, Y_1, \ldots, Y_\ell, X) = (\nabla_X F)(\omega^1, \ldots, \omega^k, Y_1, \ldots, Y_\ell) \tag{4.14}
\end{equation}
defines a smooth $(k,l+1)$-tensor field on $M$ called the \textbf{total covariant derivative} of $F$.

Let $I \subseteq \mathbb{R}$ be an open interval, and for $1 \le i,k \le n$, let $A^k_i : I \to \mathbb{R}$ be smooth functions. For all $t_0 \in I$ and every initial value $(c^1, \ldots, c^n) \in \mathbb{R}^n$, the linear initial value problem
\begin{equation}
\dot{V}^k(t) = A^k_i(t) V^i(t),
\tag{4.20}
\end{equation}
\[
V^k(t_0) = c^k,
\]
has a unique smooth solution on all of $I$, and the solution depends smoothly on $(t, c) \in I \times \mathbb{R}^n$.

Let $M$ be a smooth manifold with or without boundary, and let $\nabla$ be a connection in $TM$. Suppose $\gamma : I \to M$ is a smooth curve and $V$ is a smooth vector field along $\gamma$. For each $t_0 \in I$,
\begin{equation}
D_t V(t_0) = \lim_{t_1 \to t_0} \frac{P_{t_1 t_0}^{\gamma} V(t_1) - V(t_0)}{t_1 - t_0}. \tag{4.24}
\end{equation}

Let $M$ be a smooth manifold with or without boundary, and let $\nabla$ be a connection in $TM$. Suppose $X$ and $Y$ are smooth vector fields on $M$. For every $p \in M$,
\begin{equation}
\nabla_X Y|_p = \lim_{h \to 0} \frac{P_{h0}^{\gamma} Y(\gamma(h)) - Y_p}{h}, \tag{4.25}
\end{equation}
where $\gamma : I \to M$ is any smooth curve such that $\gamma(0) = p$ and $\gamma'(0) = X_p$.

Suppose $M$ and $	ilde{M}$ are smooth manifolds with or without boundary. If $	ilde{
abla}$ is a connection in $T	ilde{M}$ and $\varphi : M 	o 	ilde{M}$ is a diffeomorphism, then the map $\varphi^* 	ilde{
abla} : \mathfrak{X}(M) 	imes \mathfrak{X}(M) 	o \mathfrak{X}(M)$ defined by
 egin{equation}
(\varphi^* 	ilde{
abla})_X Y = (\varphi^{-1})_* \left( 	ilde{
abla}_{\varphi_* X} (\varphi_* Y) ight) 	ag{4.26}
\end{equation}
is a connection in $TM$, called the 	extbf{pullback} of $	ilde{
abla}$ by $\varphi$.

Suppose $M \subseteq \mathbb{R}^n$ is an embedded submanifold. A smooth curve $\gamma: I \to M$ is a geodesic with respect to the tangential connection on $M$ if and only if its ordinary acceleration $\gamma''(t)$ is orthogonal to $T_{\gamma(t)}M$ for all $t \in I$.

\begin{proof}
As noted in Example 4.8, the connection coefficients of the Euclidean connection on $\mathbb{R}^n$ are all zero. Thus it follows from (4.15) that the Euclidean covariant derivative of $\gamma'$ along $\gamma$ is just its ordinary acceleration: $\overline{\nabla}_{\gamma'}\gamma'(t) = \gamma''(t)$. The corollary then follows from Proposition~\ref{prop:tangential-covariant-derivative-projection}.
\end{proof}

Suppose $(M,g)$ is a Riemannian or pseudo-Riemannian manifold with or without boundary, $\nabla$ is a metric connection on $M$, and $\gamma : I \to M$ is a smooth curve.
\begin{enumerate}
\item[(a)] $|\gamma'(t)|$ is constant if and only if $D_t\gamma'(t)$ is orthogonal to $\gamma'(t)$ for all $t \in I$.
\item[(b)] If $\gamma$ is a geodesic, then $|\gamma'(t)|$ is constant.
\end{enumerate}

If $M$ is an embedded Riemannian or pseudo-Riemannian submanifold of $\mathbb{R}^n$ or $\mathbb{R}^{r,s}$, the tangential connection on $M$ is compatible with the induced Riemannian or pseudo-Riemannian metric.

\begin{proof}
We will show that $\nabla^{\top}$ satisfies (5.1). Suppose $X, Y, Z \in \mathfrak{X}(M)$, and let $\tilde{X}, \tilde{Y}, \tilde{Z}$ be smooth extensions of them to an open subset of $\mathbb{R}^n$ or $\mathbb{R}^{r,s}$. At points of $M$, we have
\begin{align*}
\nabla^{\top}_X \langle Y, Z \rangle &= X \langle Y, Z \rangle = \tilde{X} \langle \tilde{Y}, \tilde{Z} \rangle \\
&= \overline{\nabla}_{\tilde{X}} \langle \tilde{Y}, \tilde{Z} \rangle \\
&= \langle \overline{\nabla}_{\tilde{X}} \tilde{Y}, \tilde{Z} \rangle + \langle \tilde{Y}, \overline{\nabla}_{\tilde{X}} \tilde{Z} \rangle \\
&= \langle \pi^{\top} (\overline{\nabla}_{\tilde{X}} \tilde{Y}), \tilde{Z} \rangle + \langle \tilde{Y}, \pi^{\top} (\overline{\nabla}_{\tilde{X}} \tilde{Z}) \rangle \\
&= \langle \nabla^{\top}_X Y, Z \rangle + \langle Y, \nabla^{\top}_X Z \rangle,
\end{align*}
where the next-to-last equality follows from the fact that $\tilde{Z}$ and $\tilde{Y}$ are tangent to $M$.
\end{proof}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian manifold (with or without boundary). There exists a unique connection $\nabla$ on $TM$ that is compatible with $g$ and symmetric. It is called the \textbf{Levi-Civita connection} of $g$ (or also, when $g$ is positive definite, the \textbf{Riemannian connection}).

\begin{proof}
We prove uniqueness first, by deriving a formula for $\nabla$. Suppose, therefore, that $\nabla$ is such a connection, and let $X, Y, Z \in \mathfrak{X}(M)$. Writing the compatibility equation three times with $X, Y, Z$ cyclically permuted, we obtain
\begin{align*}
X\langle Y, Z \rangle &= \langle \nabla_X Y, Z \rangle + \langle Y, \nabla_X Z \rangle, \\
Y\langle Z, X \rangle &= \langle \nabla_Y Z, X \rangle + \langle Z, \nabla_Y X \rangle, \\
Z\langle X, Y \rangle &= \langle \nabla_Z X, Y \rangle + \langle X, \nabla_Z Y \rangle.
\end{align*}
Using the symmetry condition on the last term in each line, this can be rewritten as
\begin{align*}
X\langle Y, Z \rangle &= \langle \nabla_X Y, Z \rangle + \langle Y, \nabla_Z X \rangle + \langle Y, [X, Z] \rangle, \\
Y\langle Z, X \rangle &= \langle \nabla_Y Z, X \rangle + \langle Z, \nabla_X Y \rangle + \langle Z, [Y, X] \rangle, \\
Z\langle X, Y \rangle &= \langle \nabla_Z X, Y \rangle + \langle X, \nabla_Y Z \rangle + \langle X, [Z, Y] \rangle.
\end{align*}
Adding the first two of these equations and subtracting the third, we obtain
\[
X\langle Y, Z \rangle + Y\langle Z, X \rangle - Z\langle X, Y \rangle =
2\langle \nabla_X Y, Z \rangle + \langle Y, [X, Z] \rangle + \langle Z, [Y, X] \rangle - \langle X, [Z, Y] \rangle.
\]
Finally, solving for $\langle \nabla_X Y, Z \rangle$, we get
\begin{align}
\langle \nabla_X Y, Z \rangle &= \tfrac{1}{2}\bigl(X\langle Y, Z \rangle + Y\langle Z, X \rangle - Z\langle X, Y \rangle \notag \\
&\quad - \langle Y, [X, Z] \rangle - \langle Z, [Y, X] \rangle + \langle X, [Z, Y] \rangle\bigr). \tag{5.5}
\end{align}
Now suppose $\nabla^1$ and $\nabla^2$ are two connections on $TM$ that are symmetric and compatible with $g$. Since the right-hand side of~(5.5) does not depend on the connection, it follows that $\langle \nabla^1_X Y - \nabla^2_X Y, Z\rangle = 0$ for all $X, Y, Z$. This can happen only if $\nabla^1_X Y = \nabla^2_X Y$ for all $X$ and $Y$, so $\nabla^1 = \nabla^2$.

To prove existence, we use (5.5), or rather a coordinate version of it. It suffices to prove that such a connection exists in each coordinate chart, for then uniqueness ensures that the connections in different charts agree where they overlap.

Let $(U, (x^i))$ be any smooth local coordinate chart. Applying (5.5) to the coordinate vector fields, whose Lie brackets are zero, we obtain
\begin{equation}
\langle \nabla_{\partial_i} \partial_j, \partial_l \rangle = \frac{1}{2}\left(\partial_i \langle \partial_j, \partial_l \rangle + \partial_j \langle \partial_l, \partial_i \rangle - \partial_l \langle \partial_i, \partial_j \rangle\right). \tag{5.6}
\end{equation}
Recall the definitions of the metric coefficients and the connection coefficients:
\[
g_{ij} = \langle \partial_i, \partial_j \rangle, \qquad \nabla_{\partial_i} \partial_j = \Gamma^m_{ij} \partial_m.
\]
Inserting these into (5.6) yields
\begin{equation}
\Gamma^m_{ij} g_{ml} = \frac{1}{2}\left(\partial_i g_{jl} + \partial_j g_{il} - \partial_l g_{ij}\right). \tag{5.7}
\end{equation}
Finally, multiplying both sides by the inverse matrix $g^{kl}$ and noting that $g_{ml} g^{kl} = \delta^k_m$, we get
\begin{equation}
\Gamma^k_{ij} = \frac{1}{2} g^{kl}\left(\partial_i g_{jl} + \partial_j g_{il} - \partial_l g_{ij}\right). \tag{5.8}
\end{equation}
This formula certainly defines a connection in each chart, and it is evident from the formula that $\Gamma^k_{ij} = \Gamma^k_{ji}$, so the connection is symmetric by Problem 4-6(b). Thus only compatibility with the metric needs to be checked. Using (5.7) twice, we get
\[
\Gamma^l_{ki} g_{lj} + \Gamma^l_{kj} g_{il} = \frac{1}{2}\left(\partial_k g_{ij} + \partial_i g_{kj} - \partial_j g_{ki}\right) + \frac{1}{2}\left(\partial_k g_{ji} + \partial_j g_{ki} - \partial_i g_{kj}\right)
= \partial_k g_{ij}.
\]
By Proposition~\ref{prop:characterizations-of-metric-connections}(c), this shows that $\nabla$ is compatible with $g$.
\end{proof}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian manifold (with or without boundary), and let $\nabla$ be its Levi-Civita connection.

\begin{enumerate}
\item[(a)] \textbf{In terms of vector fields:} If $X, Y, Z$ are smooth vector fields on $M$, then
\begin{equation}
\langle \nabla_X Y, Z \rangle = \frac{1}{2}\bigl(X\langle Y,Z\rangle + Y\langle Z,X\rangle - Z\langle X,Y\rangle
- \langle Y,[X,Z]\rangle - \langle Z,[Y,X]\rangle + \langle X,[Z,Y]\rangle\bigr). \tag{5.9}
\end{equation}
(This is known as \textbf{Koszul's formula}.)

\item[(b)] \textbf{In coordinates:} In any smooth coordinate chart for $M$, the coefficients of the Levi-Civita connection are given by
\begin{equation}
\Gamma^k_{ij} = \frac{1}{2} g^{kl}(\partial_i g_{jl} + \partial_j g_{il} - \partial_l g_{ij}). \tag{5.10}
\end{equation}

\item[(c)] \textbf{In a local frame:} Let $(E_i)$ be a smooth local frame on an open subset $U \subseteq M$, and let $c^k_{ij} : U \to \mathbb{R}$ be the $n^3$ smooth functions defined by
\begin{equation}
[E_i, E_j] = c^k_{ij} E_k. \tag{5.11}
\end{equation}
Then the coefficients of the Levi-Civita connection in this frame are
\begin{equation}
\Gamma^k_{ij} = \frac{1}{2} g^{kl}\left(E_i g_{jl} + E_j g_{il} - E_l g_{ij} - g_{jm}c^m_{il} - g_{lm}c^m_{ji} + g_{im}c^m_{lj}\right). \tag{5.12}
\end{equation}

\item[(d)] \textbf{In a local orthonormal frame:} If $g$ is Riemannian, $(E_i)$ is a smooth local orthonormal frame, and the functions $c^k_{ij}$ are defined by (5.11), then
\begin{equation}
\Gamma^k_{ij} = \frac{1}{2}(c^k_{ij} - c^l_{ik} - c^l_{jk}). \tag{5.13}
\end{equation}
\end{enumerate}

\begin{proof}
We derived (5.9) and (5.10) in the proof of Theorem~\ref{thm:fundamental-theorem-riemannian-geometry}. To prove (5.12), apply formula (5.9) with $X = E_i$, $Y = E_j$, and $Z = E_l$, to obtain
\[
\Gamma^q_{ij}g_{ql} = \langle \nabla_{E_i} E_j, E_l \rangle
= \frac{1}{2}\left(E_i g_{jl} + E_j g_{il} - E_l g_{ij} - g_{jm}c^m_{il} - g_{lm}c^m_{ji} + g_{im}c^m_{lj}\right).
\]
Multiplying both sides by $g^{kl}$ and simplifying yields (5.12). Finally, under the hypotheses of (d), we have $g_{ij} = \delta_{ij}$, so (5.12) reduces to (5.13) after rearranging and using the fact that $c^k_{ij}$ is antisymmetric in $i, j$.
\end{proof}

\begin{enumerate}
\item[(a)] The Levi-Civita connection on a (pseudo-)Euclidean space is equal to the Euclidean connection.
\item[(b)] Suppose $M$ is an embedded (pseudo-)Riemannian submanifold of a (pseudo-)Euclidean space. Then the Levi-Civita connection on $M$ is equal to the tangential connection $\nabla^\top$.
\end{enumerate}

\begin{proof}
We observed earlier in this chapter that the Euclidean connection is symmetric and compatible with both the Euclidean metric $\overline{g}$ and the pseudo-Euclidean metrics $\overline{g}^{(r,s)}$, which implies (a). Part (b) then follows from Propositions~\ref{prop:tangential-connection-compatible-metric} and~\ref{prop:tangential-connection-symmetric}.
\end{proof}

Suppose $(M,g)$ and $(\overline{M},\overline{g})$ are Riemannian or pseudo-Riemannian manifolds with or without boundary, and $\varphi: M \to \overline{M}$ is a local isometry. If $\gamma$ is a geodesic in $M$, then $\varphi \circ \gamma$ is a geodesic in $\overline{M}$.

\begin{proof}
This is an immediate consequence of Proposition 4.38, together with the fact that being a geodesic is a local property.
\end{proof}

Let $(M, g)$ be an oriented Riemannian manifold. The Riemannian volume form of $g$ is parallel with respect to the Levi-Civita connection.

\begin{proof}
Let $p \in M$ and $v \in T_p M$ be arbitrary, and let $\gamma: (-\varepsilon, \varepsilon) \to M$ be a smooth curve satisfying $\gamma(0) = p$ and $\gamma'(0) = v$. Let $(E_1, \ldots, E_n)$ be a parallel oriented orthonormal frame along $\gamma$. Since $dV_g(E_1, \ldots, E_n) \equiv 1$ and $D_t E_i = 0$ along $\gamma$, formula (4.12) shows that $\nabla_v(dV_g) = D_t(dV_g)|_{t=0} = 0$.
\end{proof}

The musical isomorphisms commute with the total covariant derivative operator: if $F$ is any smooth tensor field with a contravariant $i$th index position, and $\flat$ represents the operation of lowering the $i$th index, then
\begin{equation}
\nabla(F^\flat) = (\nabla F)^\flat. \tag{5.14}
\end{equation}
Similarly, if $G$ has a covariant $i$th position and $\sharp$ denotes raising the $i$th index, then
\begin{equation}
\nabla(G^\sharp) = (\nabla G)^\sharp. \tag{5.15}
\end{equation}

\begin{proof}
The discussion on page 27 shows that $F^\flat = \operatorname{tr}(F \otimes g)$, where the trace is taken on the $i$th and last indices of $F \otimes g$. Because $g$ is parallel, for every vector field $X$ we have $\nabla_X(F \otimes g) = (\nabla_X F) \otimes g$. Because $\nabla_X$ commutes with traces, therefore,
\[
\nabla_X(F^\flat) = \nabla_X(\operatorname{tr}(F \otimes g)) = \operatorname{tr}((\nabla_X F) \otimes g) = (\nabla_X F)^\flat.
\]
This shows that when $X$ is inserted into the last index position on both sides of (5.14), the results are equal. Since $X$ is arbitrary, this proves (5.14).

Because the sharp and flat operators are inverses of each other when applied to the same index position, (5.15) follows by substituting $F = G^\sharp$ into (5.14) and applying $\sharp$ to both sides.
\end{proof}

For every $p \in M$, $v \in T_p M$, and $c,t \in \mathbb{R}$,
\begin{equation}
\gamma_{cv}(t) = \gamma_v(ct), \tag{5.16}
\end{equation}
whenever either side is defined.

\begin{proof}
If $c = 0$, then both sides of (5.16) are equal to $p$ for all $t \in \mathbb{R}$, so we may assume that $c \neq 0$. It suffices to show that $\gamma_{cv}(t)$ exists and (5.16) holds whenever the right-hand side is defined. (The same argument with the substitutions $v = c'v'$, $t = c't'$, and $c = 1/c'$ then implies that the conclusion holds when only the left-hand side is known to be defined.)

Suppose the maximal domain of $\gamma_v$ is the open interval $I \subset \mathbb{R}$. For simplicity, write $\gamma = \gamma_v$, and define a new curve $\tilde{\gamma}: c^{-1}I \to M$ by $\tilde{\gamma}(t) = \gamma(ct)$, where $c^{-1}I = \{c^{-1}t : t \in I\}$. We will show that $\tilde{\gamma}$ is a geodesic with initial point $p$ and initial velocity $cv$; it then follows by uniqueness and maximality that it must be equal to $\gamma_{cv}$.

It is immediate from the definition that $\tilde{\gamma}(0) = \gamma(0) = p$. Choose any smooth local coordinates on $M$ and write the coordinate representation of $\gamma$ as $\gamma(t) = (y^1(t), \ldots, y^n(t))$; then the chain rule gives
\[
\dot{\tilde{\gamma}}^i(t) = \frac{d}{dt} y^i(ct) = c\dot{y}^i(ct).
\]
In particular, it follows that $\dot{\tilde{\gamma}}(0) = c\dot{y}(0) = cv$.

Now let $D_t$ and $\tilde{D}_t$ denote the covariant differentiation operators along $\gamma$ and $\tilde{\gamma}$, respectively. Using the chain rule again in coordinates yields
\begin{align*}
\tilde{D}_t\dot{\tilde{\gamma}}(t) &= \left(\frac{d}{dt}\dot{\tilde{\gamma}}^k(t) + \Gamma^k_{ij}(\tilde{\gamma}(t))\dot{\tilde{\gamma}}^i(t)\dot{\tilde{\gamma}}^j(t)\right)\partial_k \\
&= \left(c^2\ddot{y}^k(ct) + c^2\Gamma^k_{ij}(\gamma(ct))\dot{y}^i(ct)\dot{y}^j(ct)\right)\partial_k \\
&= c^2 D_t\dot{\gamma}(ct) = 0.
\end{align*}
Thus $\tilde{\gamma}$ is a geodesic, so $\tilde{\gamma} = \gamma_{cv}$, as claimed.
\end{proof}

Let $(M, g)$ and $(\tilde{M}, \tilde{g})$ be Riemannian or pseudo-Riemannian manifolds, with $M$ connected. Suppose $\varphi, \psi: M \to \tilde{M}$ are local isometries such that for some point $p \in M$, we have $\varphi(p) = \psi(p)$ and $d\varphi_p = d\psi_p$. Then $\varphi = \psi$.

\begin{proof}
Problem 5-10.
\end{proof}

Let $(M,g)$ be a Riemannian or pseudo-Riemannian $n$-manifold, $p$ a point of $M$, and $U$ a normal neighborhood of $p$. For every normal coordinate chart on $U$ centered at $p$, the coordinate basis is orthonormal at $p$; and for every orthonormal basis $(b_i)$ for $T_p M$, there is a unique normal coordinate chart $(x^i)$ on $U$ such that $\partial_i|_p = b_i$ for $i = 1,\ldots,n$. In the Riemannian case, any two normal coordinate charts $(x^i)$ and $(\tilde{x}^i)$ are related by
\begin{equation}
\tilde{x}^i = A^i_j x^j \tag{5.19}
\end{equation}
for some (constant) matrix $(A^i_j) \in O(n)$.

\begin{proof}
Let $\varphi$ be a normal coordinate chart on $U$ centered at $p$, with coordinate functions $(x^i)$. By definition, this means $\varphi = B^{-1} \circ \exp_p^{-1}$, where $B: \mathbb{R}^n \to T_p M$ is the basis isomorphism determined by some orthonormal basis $(b_i)$ for $T_p M$. Note that $d\varphi_p^{-1} = d(\exp_p)_0 \circ dB_0 = B$ because $d(\exp_p)_0$ is the identity and $B$ is linear. Thus $\partial_i|_p = d\varphi_p^{-1}(\partial_i|_0) = B(\partial_i|_0) = b_i$, which shows that the coordinate basis is orthonormal at $p$. Conversely, every orthonormal basis $(b_i)$ for $T_p M$ yields a basis isomorphism $B$ and thus a normal coordinate chart $\varphi = B^{-1} \circ \exp_p^{-1}$, which satisfies $\partial_i|_p = b_i$ by the computation above.

If $\tilde{\varphi} = \tilde{B}^{-1} \circ \exp_p^{-1}$ is another such chart, then
\[
\tilde{\varphi} \circ \varphi^{-1} = \tilde{B}^{-1} \circ \exp_p^{-1} \circ \exp_p \circ B = \tilde{B}^{-1} \circ B,
\]
which is a linear isometry of $\mathbb{R}^n$ and therefore has the form (5.19) in terms of standard coordinates on $\mathbb{R}^n$. Since $(\tilde{x}^j)$ and $(x^i)$ are the same coordinates if and only if $(A^i_j)$ is the identity matrix, this shows that the normal coordinate chart associated with a given orthonormal basis is unique.
\end{proof}

Let $(M,g)$ be a Riemannian or pseudo-Riemannian $n$-manifold, and let $(U,(x^i))$ be any normal coordinate chart centered at $p \in M$.
\begin{enumerate}
\item[(a)] The coordinates of $p$ are $(0,\ldots,0)$.
\item[(b)] The components of the metric at $p$ are $g_{ij} = \delta_{ij}$ if $g$ is Riemannian, and $g_{ij} = \pm\delta_{ij}$ otherwise.
\item[(c)] For every $v = v^i \partial_i|_p \in T_p M$, the geodesic $\gamma_v$ starting at $p$ with initial velocity $v$ is represented in normal coordinates by the line
\begin{equation}
\gamma_v(t) = (tv^1,\ldots,tv^n), \tag{5.20}
\end{equation}
as long as $t$ is in some interval $I$ containing $0$ such that $\gamma_v(t) \subseteq U$.
\item[(d)] The Christoffel symbols in these coordinates vanish at $p$.
\item[(e)] All of the first partial derivatives of $g_{ij}$ in these coordinates vanish at $p$.
\end{enumerate}

\begin{proof}
Part (a) follows directly from the definition of normal coordinates, and parts (b) and (c) follow from Propositions~\ref{prop:uniqueness-normal-coordinates} and~\ref{prop:exponential-map-properties}(b), respectively.

To prove (d), let $v = v^i \partial_i|_p \in T_p M$ be arbitrary. The geodesic equation (4.16) for $\gamma_v(t) = (tv^1, \ldots, tv^n)$ simplifies to
\[
\Gamma_{ij}^k(tv) v^i v^j = 0.
\]
Evaluating this expression at $t = 0$ shows that $\Gamma_{ij}^k(0) v^i v^j = 0$ for every index $k$ and every vector $v$. In particular, with $v = \partial_a$ for some fixed $a$, this shows that $\Gamma_{aa}^k = 0$ for each $a$ and $k$ (no summation). Substituting $v = \partial_a + \partial_b$ and $v = \partial_b - \partial_a$ for any fixed pair of indices $a$ and $b$ and subtracting, we conclude also that $\Gamma_{ab}^k = 0$ at $p$ for all $a, b, k$. Finally, (e) follows from (d) together with (5.2) in the case $E_k = \partial_k$.
\end{proof}

Let $(M, g)$ be a Riemannian manifold. Every embedded submanifold of $M$ has a tubular neighborhood in $M$, and every compact submanifold has a uniform tubular neighborhood.



\begin{proof}
Let $P \subseteq M$ be an embedded submanifold, and let $P_0 \subseteq NP$ be the subset $\{(x,0) : x \in P\}$ (the image of the zero section of $NP$). We begin by showing that the normal exponential map $E$ is a local diffeomorphism on a neighborhood of $P_0$. By the inverse function theorem, it suffices to show that the differential $dE_{(x,0)}$ is bijective at each point $(x,0) \in P_0$. The restriction of $E$ to $P_0$ is just the diffeomorphism $P_0 \to P$ followed by the embedding $P \hookrightarrow M$, so $dE_{(x,0)}$ maps the subspace $T_{(x,0)}P_0 \subseteq T_{(x,0)}NP$ isomorphically onto $T_x P$. On the other hand, on the fiber $N_x P$, $E$ agrees with the restricted exponential map $\exp_x$, which is a diffeomorphism near $0$, so $dE_{(x,0)}$ maps $T_{(x,0)}(N_x P) \subseteq T_{(x,0)}NP$ isomorphically onto $N_x P$. Since $T_x M = T_x P \oplus N_x P$, this shows that $dE_{(x,0)}$ is surjective, and hence it is bijective for dimensional reasons. Thus $E$ is a diffeomorphism on a neighborhood of $(x,0)$ in $NP$, which we can take to be of the form
\begin{equation}
V_\delta(x) = \{(x', v') \in NP : d_g(x,x') < \delta, |v'|_g < \delta\} \tag{5.22}
\end{equation}
for some $\delta > 0$. (Here we are using the fact that $P$ is embedded in $M$, so it has the subspace topology.)

To complete the proof, we need to show that there is a set $V \subseteq \mathcal{E}_P$ of the form (5.21) on which $E$ is a diffeomorphism onto its image. For each point $x \in P$, define
\begin{equation}
\Delta(x) = \sup\{\delta \leq 1 : E \text{ is a diffeomorphism from } V_\delta(x) \text{ to its image}\}. \tag{5.23}
\end{equation}
The argument in the preceding paragraph implies that $\Delta(x)$ is positive for each $x$. Note that $E$ is injective on the entire set $V_{\Delta(x)}(x)$, because any two points $(x_1, v_1), (x_2, v_2)$ in this set are in $V_\delta(x)$ for some $\delta < \Delta(x)$. Because it is an injective local diffeomorphism, $E$ is actually a diffeomorphism from $V_{\Delta(x)}(x)$ onto its image.

Next we show that the function $\Delta: P \to \mathbb{R}$ is continuous. For any $x, x' \in P$, if $d_g(x,x') < \Delta(x)$, then the triangle inequality shows that $V_\delta(x')$ is contained in $V_{\Delta(x)}(x)$ for $\delta = \Delta(x) - d_g(x,x')$, which implies that $\Delta(x') \geq \Delta(x) - d_g(x,x')$, or
\begin{equation}
\Delta(x) - \Delta(x') \leq d_g(x, x'). \tag{5.24}
\end{equation}
If $d_g(x, x') \geq \Delta(x)$, then (5.24) holds for trivial reasons. Reversing the roles of $x$ and $x'$ yields an analogous inequality, which shows that $|\Delta(x) - \Delta(x')| \leq d_g(x, x')$, so $\Delta$ is continuous.

Let $V = \{(x, v) \in NP : |v|_g < \frac{1}{2}\Delta(x)\}$, which is an open subset of $NP$ containing $P_0$. We show that $E$ is injective on $V$. Suppose $(x, v)$ and $(x', v')$ are points in $V$ such that $E(x, v) = E(x', v')$ (Fig.\ 5.4). Assume without loss of generality that $\Delta(x') \leq \Delta(x)$. Because $\exp_x(v) = \exp_{x'}(v')$, there is an admissible curve from $x$ to $x'$ of length $|v|_g + |v'|_g$, and thus
\[
d_g(x, x') \leq |v|_g + |v'|_g < \frac{1}{2}\Delta(x) + \frac{1}{2}\Delta(x') \leq \Delta(x).
\]
Therefore, both $(x, v)$ and $(x', v')$ are in $V_{\Delta(x)}(x)$. Since $E$ is injective on this set, this implies $(x, v) = (x', v')$.

The set $U = E(V)$ is open in $M$ because $E|_V$ is a local diffeomorphism and thus an open map, and $E: V \to U$ is a diffeomorphism. Therefore, $U$ is a tubular neighborhood of $P$.

Finally, if $P$ is compact, then the continuous function $\frac{1}{2}\Delta$ achieves a minimum value $\varepsilon > 0$ on $P$, so $U$ contains a uniform tubular neighborhood of radius $\varepsilon$.
\end{proof}

Let $P$ be an embedded $p$-dimensional submanifold of a Riemannian $n$-manifold $(M,g)$, let $U$ be a normal neighborhood of $P$ in $M$, and let $(x^1, \ldots, x^p, v^1, \ldots, v^{n-p})$ be Fermi coordinates on an open subset $U_0 \subseteq U$. For convenience, we also write $x^{p+j} = v^j$ for $j = 1, \ldots, n-p$.
\begin{enumerate}
\item[(a)] $P \cap U_0$ is the set of points where $x^{p+1} = \cdots = x^n = 0$.
\item[(b)] At each point $q \in P \cap U_0$, the metric components satisfy the following:
\[
g_{ij} = g_{ji} = \begin{cases} 0, & 1 \le i \le p \text{ and } p+1 \le j \le n, \\ \delta_{ij}, & p+1 \le i, j \le n. \end{cases}
\]
\item[(c)] For every $q \in P \cap U_0$ and $v = v^1 E_1|_q + \cdots + v^{n-p} E_{n-p}|_q \in N_q P$, the geodesic $\gamma_v$ starting at $q$ with initial velocity $v$ is the curve with coordinate expression $\gamma_v(t) = (x^1(q), \ldots, x^p(q), tv^1, \ldots, tv^{n-p})$.
\item[(d)] At each $q \in P \cap U_0$, the Christoffel symbols in these coordinates satisfy $\Gamma^k_{ij} = 0$, provided $p+1 \le i, j \le n$.
\item[(e)] At each $q \in P \cap U_0$, the partial derivatives $\partial_i g_{jk}(q)$ vanish for $p+1 \le i, j, k \le n$.
\end{enumerate}

\begin{proof}
Problem 5-18.
\end{proof}

Let $(M,g)$ be a Riemannian manifold. Suppose $\gamma: [a,b] \to M$ is a unit-speed admissible curve, $\Gamma: J \times [a,b] \to M$ is a variation of $\gamma$, and $V$ is its variation field. Then $L_g(\Gamma_s)$ is a smooth function of $s$, and
\begin{equation}
\frac{d}{ds}\bigg|_{s=0} L_g(\Gamma_s) = -\int_a^b \langle V, D_t \gamma'\rangle \, dt - \sum_{i=1}^{k-1} \langle V(a_i), \Delta_i \gamma'\rangle + \langle V(b), \gamma'(b)\rangle - \langle V(a), \gamma'(a)\rangle, \tag{6.1}
\end{equation}
where $(a_0,\ldots,a_k)$ is an admissible partition for $\gamma$, and for each $i = 1,\ldots,k-1$, $\Delta_i \gamma' = \gamma'(a_i^+) - \gamma'(a_i^-)$ is the ``jump'' in the velocity vector field $\gamma'$ at $a_i$ (Fig. 6.3). In particular, if $\Gamma$ is a proper variation, then
\begin{equation}
\frac{d}{ds}\bigg|_{s=0} L_g(\Gamma_s) = -\int_a^b \langle V, D_t \gamma'\rangle \, dt - \sum_{i=1}^{k-1} \langle V(a_i), \Delta_i \gamma'\rangle. \tag{6.2}
\end{equation}

Suppose $(M,g)$ is a connected Riemannian manifold, and there is a point $p \in M$ such that $\exp_p$ is defined on the whole tangent space $T_p M$.
\begin{enumerate}
\item[(a)] Given any other $q \in M$, there is a minimizing geodesic segment from $p$ to $q$.
\item[(b)] $M$ is metrically complete.
\end{enumerate}

Let $P$ be an embedded submanifold of a Riemannian manifold $(M,g)$ and let $U$ be any normal neighborhood of $P$ in $M$. There exist a unique continuous function $r : U \to [0,\infty)$ and smooth vector field $\partial_r$ on $U \setminus P$ that have the following coordinate representations in terms of any Fermi coordinates $(x^1,\ldots,x^k,v^1,\ldots,v^{n-k})$ for $P$ on a subset $U_0 \subseteq U$:
\begin{equation}
r(x^1,\ldots,x^k,v^1,\ldots,v^{n-k}) = \sqrt{(v^1)^2 + \cdots + (v^{n-k})^2}, \tag{6.17}
\end{equation}
\begin{equation}
\partial_r = \frac{v^1}{r(x,v)} \frac{\partial}{\partial v^1} + \cdots + \frac{v^{n-k}}{r(x,v)} \frac{\partial}{\partial v^{n-k}}. \tag{6.18}
\end{equation}

The function $r$ is smooth on $U \setminus P$, and $r^2$ is smooth on all of $U$.

\begin{enumerate}
\item[(a)] $\partial_r$ is equal to the gradient of $r$ on $U \setminus P$.
\item[(b)] $r$ is a local distance function.
\item[(c)] Each unit-speed geodesic $\gamma : [a, b] \to U$ with $\gamma'(a)$ normal to $P$ coincides with an integral curve of $\partial_r$ on $(a,b)$.
\item[(d)] $P$ has a tubular neighborhood in which the distance in $M$ to $P$ is equal to $r$.
\end{enumerate}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian manifold. In terms of any smooth local coordinates, the components of the $(1,3)$-curvature tensor are given by
\begin{equation}
R_{ijk}^l = \partial_i \Gamma_{jk}^l - \partial_j \Gamma_{ik}^l + \Gamma_{jk}^m \Gamma_{im}^l - \Gamma_{ik}^m \Gamma_{jm}^l. \tag{7.4}
\end{equation}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian manifold; let $I$ be an open interval containing $0$; let $\Gamma: I \times I \to M$ be a smooth one-parameter family of curves; and let $p = \Gamma(0,0)$, $x = \partial_s \Gamma(0,0)$, and $y = \partial_t \Gamma(0,0)$. For any $s_1, s_2, t_1, t_2 \in I$, let $P^{s_1,t_2}_{s_1,t_1}: T_{\Gamma(s_1,t_1)} M \to T_{\Gamma(s_1,t_2)} M$ denote parallel transport along the curve $t \mapsto \Gamma(s_1, t)$ from time $t_1$ to time $t_2$, and let $P^{s_2,t_1}_{s_1,t_1}: T_{\Gamma(s_1,t_1)} M \to T_{\Gamma(s_2,t_1)} M$ denote parallel transport along the curve $s \mapsto \Gamma(s, t_1)$ from time $s_1$ to time $s_2$. (See Fig. 7.3.) Then for every $z \in T_p M$,
\begin{equation}
R(x,y)z = \lim_{\delta, \varepsilon \to 0} \frac{P^{0,0}_{\delta,0} \circ P^{\delta,0}_{\delta,\varepsilon} \circ P^{\delta,\varepsilon}_{0,\varepsilon} \circ P^{0,\varepsilon}_{0,0}(z) - z}{\delta\varepsilon}.
\tag{7.10}
\end{equation}

The total covariant derivative of the curvature tensor satisfies the following identity:
\begin{equation}
\nabla Rm(X, Y, Z, V, W) + \nabla Rm(X, Y, V, W, Z) + \nabla Rm(X, Y, W, Z, V) = 0. \tag{7.14}
\end{equation}
In components, this is
\begin{equation}
R_{ijkl;m} + R_{ijlm;k} + R_{ijmk;l} = 0. \tag{7.15}
\end{equation}

On a Riemannian or pseudo-Riemannian manifold $M$, the second total covariant derivatives of vector and tensor fields satisfy the following identities. If $Z$ is a smooth vector field,
$$\nabla^2_{X,Y} Z - \nabla^2_{Y,X} Z = R(X,Y)Z. \quad (7.17)$$
If $\beta$ is a smooth $1$-form,
$$\nabla^2_{X,Y} \beta - \nabla^2_{Y,X} \beta = -R(X,Y)^* \beta. \quad (7.18)$$
And if $B$ is a smooth $(k, l)$-tensor field,
\[
(\nabla^2_{X,Y} B - \nabla^2_{Y,X} B)(\omega^1,\ldots,\omega^k, V_1,\ldots, V_l)
= B(R(X,Y)^* \omega^1, \omega^2,\ldots,\omega^k, V_1,\ldots,V_l) + \cdots
\]
\begin{equation}
+ B(\omega^1,\ldots,\omega^{k-1}, R(X,Y)^* \omega^k, V_1,\ldots, V_l) \tag{7.19}
\end{equation}
\[
- B(\omega^1,\ldots,\omega^k, R(X,Y)V_1, V_2,\ldots, V_l) - \cdots
- B(\omega^1,\ldots,\omega^k, V_1,\ldots, V_{l-1}, R(X,Y)V_l),
\]
for all covector fields $\omega^i$ and vector fields $V_j$. In terms of any local frame, the component versions of these formulas read
\begin{equation}
Z^i_{;pq} - Z^i_{;qp} = -R_{pqm}^i Z^m, \tag{7.20}
\end{equation}
\begin{equation}
\beta_{j;pq} - \beta_{j;qp} = R_{pqj}^m \beta_m, \tag{7.21}
\end{equation}
\[
B^{i_1\cdots i_k}_{j_1\cdots j_l;pq} - B^{i_1\cdots i_k}_{j_1\cdots j_l;qp} = -R_{pqm}^{i_1} B^{m i_2 \cdots i_k}_{j_1\cdots j_l} - \cdots - R_{pqm}^{i_k} B^{i_1\cdots i_{k-1}m}_{j_1\cdots j_l}
\]
\begin{equation}
\hphantom{B^{i_1\cdots i_k}_{j_1\cdots j_l;pq} - B^{i_1\cdots i_k}_{j_1\cdots j_l;qp} =} + R_{pqj_1}^m B^{i_1\cdots i_k}_{m j_2\cdots j_l} + \cdots + R_{pqj_l}^m B^{i_1\cdots i_k}_{j_1\cdots j_{l-1}m}. \tag{7.22}
\end{equation}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian $n$-manifold. Then $\mathrm{tr}_g \stackrel{\circ}{\text{Rc}} \equiv 0$, and the Ricci tensor decomposes orthogonally as
\begin{equation}
\text{Rc} = \stackrel{\circ}{\text{Rc}} + \frac{1}{n}Sg. \tag{7.27}
\end{equation}
Therefore, in the Riemannian case,
\begin{equation}
|\text{Rc}|_g^2 = |\stackrel{\circ}{\text{Rc}}|_g^2 + \frac{1}{n}S^2. \tag{7.28}
\end{equation}

If the vector space $V$ has dimension $n$, then
\begin{equation}
\dim \mathscr{R}(V^*) = \frac{n^2(n^2-1)}{12}. \tag{7.36}
\end{equation}

Let $(V,g)$ be an $n$-dimensional scalar product space with $n \geq 3$, and define a linear map $G: \Sigma^2(V^*) \to \mathcal{R}(V^*)$ by
\begin{equation}
G(h) = \frac{1}{n-2}\left(h - \frac{\operatorname{tr}_g h}{2(n-1)}g\right) \owedge g. \tag{7.38}
\end{equation}
Then $G$ is a right inverse for $\operatorname{tr}_g$, and its image is the orthogonal complement of the kernel of $\operatorname{tr}_g$ in $\mathcal{R}(V^*)$.

Let $V$ be an $n$-dimensional real vector space.
\begin{enumerate}
\item[(a)] If $n = 0$ or $n = 1$, then $\mathfrak{R}(V^*) = \{0\}$.
\item[(b)] If $n = 2$, then $\mathfrak{R}(V^*)$ is 1-dimensional, spanned by $g \owedge g$.
\item[(c)] If $n = 3$, then $\mathfrak{R}(V^*)$ is 6-dimensional, and $G: \Sigma^2(V^*) \to \mathfrak{R}(V^*)$ is an isomorphism.
\end{enumerate}

On every Riemannian or pseudo-Riemannian manifold $(M, g)$ of dimension 3, the Weyl tensor is zero, and the Riemann curvature tensor is determined by the Ricci tensor via the formula
\begin{equation}
\text{Rm} = P \owedge g = \text{Rc} \owedge g - \frac{1}{4} S \, g \owedge g. \tag{7.39}
\end{equation}

Let $(M,g)$ be a Riemannian or pseudo-Riemannian manifold of dimension $n \geq 3$. Then the $(0,4)$-curvature tensor of $g$ has the following orthogonal decomposition:
\begin{equation}
Rm = W + \frac{1}{n-2}\stackrel{\circ}{\mathrm{Rc}} \owedge g + \frac{1}{2n(n-1)}S g \owedge g. \tag{7.40}
\end{equation}
Therefore, in the Riemannian case,
\[
|Rm|_g^2 = |W|_g^2 + \frac{1}{(n-2)^2}|\stackrel{\circ}{\mathrm{Rc}} \owedge g|_g^2 + \frac{1}{4n^2(n-1)^2}|S g \owedge g|_g^2
\]
\begin{equation}
= |W|_g^2 + \frac{4}{n-2}|\stackrel{\circ}{\mathrm{Rc}}|_g^2 + \frac{2}{n(n-1)}S^2. \tag{7.41}
\end{equation}

Suppose $(M,g)$ is a Riemannian or pseudo-Riemannian manifold of dimension $n \geq 3$, and let $W$ and $C$ denote its Weyl and Cotton tensors, respectively. Then
\begin{equation}
\mathrm{tr}_g(\nabla W) = (n-3)C,
\tag{7.50}
\end{equation}
where the trace is on the first and last indices of the 5-tensor $\nabla W$.

Suppose $(M,g)$ is a Riemannian or pseudo-Riemannian manifold of dimension $n \geq 3$.
\begin{enumerate}
\item[(a)] If $n \geq 4$, then $(M,g)$ is locally conformally flat if and only if its Weyl tensor is identically zero.
\item[(b)] If $n = 3$, then $(M,g)$ is locally conformally flat if and only if its Cotton tensor is identically zero.
\end{enumerate}

Suppose $(M,g)$ is an embedded Riemannian submanifold of a Riemannian or pseudo-Riemannian manifold $(\bar{M}, \bar{g})$, and $\gamma : I \to M$ is a smooth curve. If $X$ is a smooth vector field along $\gamma$ that is everywhere tangent to $M$, then
\begin{equation}
\bar{D}_t X = D_t X + \Pi(\gamma', X).
\tag{8.2}
\end{equation}

Suppose $(M,g)$ is an embedded Riemannian submanifold of a Riemannian or pseudo-Riemannian manifold $(\bar{M}, \bar{g})$. For every $X \in \mathfrak{X}(M)$ and $N \in \Gamma(NM)$, the following equation holds:
\begin{equation}
(\widetilde{\nabla}_X N)^T = -W_N(X),
\tag{8.5}
\end{equation}
when $N$ is extended arbitrarily to an open subset of $\widetilde{M}$.

Suppose $(M, g)$ is an embedded Riemannian submanifold of a Riemannian or pseudo-Riemannian manifold $(\bar{M}, \bar{g})$. For all $W, X, Y \in \mathfrak{X}(M)$, the following equation holds:
\begin{equation}
(\bar{R}(W, X)Y)^{\perp} = (\nabla_W^{\perp} \Pi)(X, Y) - (\nabla_X^{\perp} \Pi)(W, Y).
\tag{8.6}
\end{equation}

Suppose $M \subseteq \mathbb{R}^{n+1}$ is an embedded hypersurface, $X: U \to M$ is a smooth local parametrization of $M$, $(X_1,\ldots,X_n)$ is the local frame for $TM$ determined by $X$, and $N$ is a unit normal field on $M$. Then the scalar second fundamental form is given by
\begin{equation}
h(X_i, X_j) = \left\langle \frac{\partial^2 X}{\partial u^i \partial u^j}, N \right\rangle.
\tag{8.23}
\end{equation}

Suppose $M \subset \mathbb{R}^{n+1}$ is a Riemannian hypersurface. Let $p \in M$, and let $k_1, \ldots, k_n$ denote the principal curvatures of $M$ at $p$ with respect to some choice of unit normal. Then there is an isometry $\varphi: \mathbb{R}^{n+1} \to \mathbb{R}^{n+1}$ that takes $p$ to the origin and takes a neighborhood of $p$ in $M$ to a graph of the form $x^{n+1} = f(x^1, \ldots, x^n)$, where
\begin{equation}
f(x) = \frac{1}{2}(k_1(x^1)^2 + \cdots + k_n(x^n)^2) + O(|x|^3).
\tag{8.24}
\end{equation}

Let $(M, g)$ be a Riemannian $n$-manifold and $p \in M$.

\begin{enumerate}
\item[(a)] For every unit vector $v \in T_p M$, $\text{Rc}_p(v,v)$ is the sum of the sectional curvatures of the 2-planes spanned by $(v,b_2), \ldots, (v,b_n)$, where $(b_1, \ldots, b_n)$ is any orthonormal basis for $T_p M$ with $b_1 = v$.

\item[(b)] The scalar curvature at $p$ is the sum of all sectional curvatures of the 2-planes spanned by ordered pairs of distinct basis vectors in any orthonormal basis.
\end{enumerate}

The following Riemannian manifolds have the indicated constant sectional curvatures:
\begin{enumerate}
\item[(a)] $(\mathbb{R}^n, \bar{g})$ has constant sectional curvature $0$.
\item[(b)] $(\mathbb{S}^n(R), \bar{g}_R)$ has constant sectional curvature $1/R^2$.
\item[(c)] $(\mathbb{H}^n(R), \bar{g}_R)$ has constant sectional curvature $-1/R^2$.
\end{enumerate}

Let $(M, g)$ be an oriented Riemannian 2-manifold. Suppose $\gamma$ is a positively oriented curved polygon in $M$, and $\Omega$ is its interior. Then
\begin{equation}
\int_\Omega K \, dA + \int_\gamma \kappa_N \, ds + \sum_{i=1}^k \varepsilon_i = 2\pi,
\tag{9.6}
\end{equation}
where $K$ is the Gaussian curvature of $g$, $dA$ is its Riemannian volume form,
$\varepsilon_1, \ldots, \varepsilon_k$ are the exterior angles of $\gamma$, and the second integral is taken with respect
to arc length (Problem 2-32).

Let $(M,g)$ be a compact Riemannian $2$-manifold and let $K$ be its Gaussian curvature.

\begin{enumerate}
\item[(a)] If $M$ is homeomorphic to the sphere or the projective plane, then $K > 0$ somewhere.
\item[(b)] If $M$ is homeomorphic to the torus or the Klein bottle, then either $K \equiv 0$ or $K$ takes on both positive and negative values.
\item[(c)] If $M$ is any other compact surface, then $K < 0$ somewhere.
\end{enumerate}

Let $(M,g)$ be a compact Riemannian $2$-manifold and $K$ its Gaussian curvature.

\begin{enumerate}
\item[(a)] If $K > 0$ everywhere on $M$, then the universal covering manifold of $M$ is homeomorphic to $S^2$, and $\pi_1(M)$ is either trivial or isomorphic to the two-element group $\mathbb{Z}/2$.
\item[(b)] If $K \le 0$ everywhere on $M$, then the universal covering manifold of $M$ is homeomorphic to $\mathbb{R}^2$, and $\pi_1(M)$ is infinite.
\end{enumerate}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian manifold. Suppose $\gamma: I \to M$ is a geodesic and $J$ is a Jacobi field along $\gamma$. Then the following are equivalent:

\begin{enumerate}
\item[(a)] $J$ is a normal Jacobi field.
\item[(b)] $J$ is orthogonal to $\gamma'$ at two distinct points.
\item[(c)] Both $J$ and $D_t J$ are orthogonal to $\gamma'$ at one point.
\item[(d)] Both $J$ and $D_t J$ are orthogonal to $\gamma'$ everywhere along $\gamma$.
\end{enumerate}

\begin{proof}
Define a function $f: I \to \mathbb{R}$ by $f(t) = \langle J(t), \gamma'(t) \rangle$, so that $f(t) = 0$ if and only if $J(t) \perp \gamma'(t)$. Using compatibility with the metric and the fact that $D_t \gamma' \equiv 0$, we compute
\begin{align*}
f'' &= \langle D_t^2 J, \gamma' \rangle \\
&= -\langle R(J, \gamma') \gamma', \gamma' \rangle \\
&= -\mathrm{Rm}(J, \gamma', \gamma', \gamma') = 0
\end{align*}
by the symmetries of the curvature tensor. Thus, by elementary calculus, $f$ is an affine function of $t$.

Note that $f'(t) = \langle D_t J(t), \gamma'(t) \rangle$, which vanishes at $t$ if and only if $D_t J(t) \perp \gamma'(t)$. It follows that $J(a)$ and $D_t J(a)$ are orthogonal to $\gamma'(a)$ for some $a \in I$ if and only if $f$ and its first derivative vanish at $a$, which happens if and only if $f \equiv 0$. Similarly, $J$ is orthogonal to $\gamma'$ at two points if and only if $f$ vanishes at two points, which happens if and only if $f$ is identically zero. If this is the case, then $f' \equiv 0$ as well, which implies that both $J$ and $D_t J$ are orthogonal to $\gamma'$ for all $t$.
\end{proof}

Suppose $(M, g)$ is a Riemannian or pseudo-Riemannian $n$-manifold and $\gamma: I \to M$ is any nonconstant geodesic. Then $J^{\perp}(\gamma)$ is a $(2n-2)$-dimensional subspace of $J(\gamma)$, and $J^T(\gamma)$ is a 2-dimensional subspace. Every Jacobi field can be uniquely decomposed as a sum of a tangential Jacobi field plus a normal Jacobi field.

\begin{proof}
As we noted in the proof of Corollary 10.3, for every $a \in I$, the map from $J(\gamma)$ to $T_{\gamma(a)} M \oplus T_{\gamma(a)} M$ given by $J \mapsto (J(a), D_t J(a))$ is an isomorphism, and Proposition 10.7 shows that $J^{\perp}(\gamma)$ is exactly the preimage of the subspace consisting of all pairs $(v, w) \in T_{\gamma(a)} M \oplus T_{\gamma(a)} M$ such that $\langle v, \gamma'(a) \rangle = \langle w, \gamma'(a) \rangle = 0$. Because this subspace has dimension $2n-2$, it follows that $J^{\perp}(\gamma)$ has the same dimension.

On the other hand, $J^T(\gamma)$ contains $J_0(t) = \gamma'(t)$ and $J_1(t) = t \gamma'(t)$, which are linearly independent over $\mathbb{R}$ because $\gamma'(t)$ never vanishes, so it is a subspace of dimension at least 2. Because $J^{\perp}(\gamma) \cap J^T(\gamma) = \{0\}$, the dimension of $J^T(\gamma)$ must be exactly 2, and we have a direct sum decomposition $J(\gamma) = J^{\perp}(\gamma) \oplus J^T(\gamma)$. This implies that every $J \in J(\gamma)$ has a unique decomposition $J = J^{\perp} + J^T$, with $J^{\perp} \in J^{\perp}(\gamma)$ and $J^T \in J^T(\gamma)$.
\end{proof}

Let $(M, g)$ be a Riemannian or pseudo-Riemannian $n$-manifold and $p \in M$. Suppose $\gamma : I \to M$ is a geodesic such that $0 \in I$ and $\gamma(0) = p$. For every $w \in T_p M$, the Jacobi field $J$ along $\gamma$ such that $J(0) = 0$ and $D_t J(0) = w$ is given by
$$J(t) = d(\exp_p)_{tv}(tw), \quad (10.6)$$
where $v = \gamma'(0)$, and we regard $tw$ as an element of $T_{tv}(T_p M)$ by means of the canonical identification $T_{tv}(T_p M) \cong T_p M$. If $(x^i)$ are normal coordinates on a normal neighborhood of $p$ containing the image of $\gamma$, then $J$ is given by the formula
\begin{equation}
J(t) = tw^i\partial_i\bigg|_{\gamma(t)}, \tag{10.7}
\end{equation}
where $w^i \partial_i\big|_0$ is the coordinate representation of $w$.

Suppose $(M, g)$ is a Riemannian manifold with constant sectional curvature $c$, and $\gamma$ is a unit-speed geodesic in $M$. The normal Jacobi fields along $\gamma$ vanishing at $t = 0$ are the vector fields of the form
\begin{equation}
J(t) = k s_c(t) E(t), \tag{10.9}
\end{equation}
where $E$ is any parallel unit normal vector field along $\gamma$, $k$ is an arbitrary constant, and $s_c$ is defined by (10.8). The initial derivative of such a Jacobi field is
\begin{equation}
D_t J(0) = kE(0),
\tag{10.10}
\end{equation}
and its norm is
\begin{equation}
|J(t)| = |s_c(t)| |D_t J(0)|.
\tag{10.11}
\end{equation}

\begin{enumerate}
\item[(a)] If $(S^n(R), \dot{g}_R)$ is a sphere with a round metric, the cut locus of every point $p \in S^n(R)$ is the singleton set containing only the antipodal point $-p$.

\item[(b)] On a product space $S^n(R) \times \mathbb{R}^m$ with the product metric, the cut locus of every point $(p, x)$ is the set $\{-p\} \times \mathbb{R}^m$. The case $n = m = 1$ is illustrated in Figure 10.10. //
\end{enumerate}

Suppose $(M, g)$ is a complete, connected Riemannian manifold, $p \in M$, and $v$ is a unit vector in $T_p M$. Let $c = t_{\text{cut}}(p, v) \in (0, \infty]$.

\begin{enumerate}
\item[(a)] If $0 < b < c$, then $\gamma_v|_{[0,b]}$ has no conjugate points and is the unique unit-speed minimizing curve between its endpoints.

\item[(b)] If $c < \infty$, then $\gamma_v|_{[0,c]}$ is minimizing, and one or both of the following conditions are true:
\begin{itemize}
\item $\gamma_v(c)$ is conjugate to $p$ along $\gamma_v$.
\item There are two or more unit-speed minimizing geodesics from $p$ to $\gamma_v(c)$.
\end{itemize}
\end{enumerate}

\begin{proof}
Suppose first that $0 < b < c$. By definition of $t_{\text{cut}}(p, v)$, there is a time $b'$ such that $b < b' < c$ and $\gamma_v|_{[0,b']}$ is minimizing. Then $\gamma_v(t)$ cannot be conjugate to $p$ along $\gamma_v$ for any $0 \le t \le b$ (Thm. 10.26), and $\gamma_v|_{[0,b]}$ is minimizing because a shorter admissible curve from $p$ to $\gamma_v(b)$ could be combined with $\gamma_v|_{[b,b']}$ to produce a shorter admissible curve from $p$ to $\gamma_v(b')$, contradicting the fact that $\gamma_v|_{[0,b']}$ is minimizing.

To see that $\gamma_v|_{[0,b]}$ is the unique unit-speed minimizing curve between its endpoints, suppose for the sake of contradiction that $\sigma: [0, b] \to M$ is another. Note that $\sigma'(b) \ne \gamma_v'(b)$, since otherwise $\sigma$ and $\gamma_v$ would agree on $[0, b]$ by uniqueness of geodesics. Define a new unit-speed admissible curve $\tilde{\gamma}: [0, b'] \to M$ that is equal to $\sigma(t)$ for $t \in [0, b]$ and equal to $\gamma_v(t)$ for $t \in [b, b']$. Then $\tilde{\gamma}$ has length $b'$, so it is also a minimizing curve from $p$ to $\gamma_v(b')$; but it is not smooth at $t = b$, contradicting the fact that minimizing curves are smooth geodesics. This completes the proof of (a).

Now suppose $c < \infty$. By definition of $t_{\text{cut}}(\rho, v)$, there is a sequence of times $b_i \nearrow c$ such that the restriction of $\gamma_v$ to $[0,b_i]$ is minimizing. By continuity of the distance function, therefore,
\[d_g(p, \gamma_v(c)) = \lim_{i \to \infty} d_g(p, \gamma_v(b_i)) = \lim_{i \to \infty} b_i = c,\]
which shows that $\gamma_v$ is minimizing on $[0,c]$. To prove that one of the options in (b) must hold, assume that $\gamma_v(c)$ is not conjugate to $p$ along $\gamma_v$. We will prove the existence of a second unit-speed minimizing geodesic from $p$ to $\gamma_v(c)$.

Let $(b_i)$ be a sequence of real numbers such that $b_i \searrow c$. By definition of cut time, $\gamma_v|_{[0,b_i]}$ is not minimizing, so for each $i$ there is a unit-speed minimizing geodesic $\sigma_i: [0,a_i] \to M$ such that $\sigma_i(0) = p$, $\sigma_i(a_i) = \gamma_v(b_i)$, and $a_i < b_i$. Set $w_i = \sigma'_i(0) \in T_p M$, so each $w_i$ is a unit vector. By compactness of the unit sphere, after passing to a subsequence we may assume that $w_i$ converges to some unit vector $w$. Since the $a_i$'s are all positive and bounded above by $b_i$, by passing to a further subsequence, we may also assume that $a_i$ converges to some number $a$. Then by continuity of the exponential map, $\sigma_i(a_i) = \exp_p(a_i w_i)$ converges to $\exp_p(aw)$. But we also know that $\sigma_i(a_i) = \gamma_v(b_i)$, which converges to $\gamma_v(c)$, so $\exp_p(aw) = \gamma_v(c)$. Moreover, by continuity of the distance function,
\[c = d_g(p, \gamma_v(c)) = \lim_{i \to \infty} d_g(p, \sigma_i(a_i)) = \lim_{i \to \infty} a_i = a.\]

Thus $\sigma: [0,c] \to M$ given by $\sigma(t) = \exp_p(tw)$ is also a unit-speed minimizing geodesic from $p$ to $\gamma_v(c)$. We need to show that it is not equal to $\gamma_v$.

The assumption that $\gamma_v(c)$ is not conjugate to $p$ along $\gamma_v$ implies that $cv$ is a regular point of $\exp_p$ (Prop.\ 10.20), so $\exp_p$ is injective in some neighborhood $V$ of $cv$. Note that $\exp_p(a_i w_i) = \exp_p(b_i v)$ for each $i$, while $a_i w_i \ne b_i v$, since $w_i$ and $v$ are unit vectors and $a_i < b_i$. Since $b_i v$ converges to $cv$, we conclude that $b_i v \in V$ for sufficiently large $i$, and thus by injectivity $a_i w_i \notin V$ for these values of $i$. Therefore $cw = \lim_{i \to \infty} a_i w_i \ne cv$, which implies $w \ne v$ and thus $\sigma \ne \gamma_v$, as claimed. $\square$
\end{proof}

Every compact, connected, smooth $n$-manifold is homeomorphic to a quotient space of $\mathbb{R}^n$ by an equivalence relation that identifies only points on the boundary.

\begin{proof}
Let $M$ be a compact, connected, smooth $n$-manifold, let $p$ be any point of $M$, and let $g$ be any Riemannian metric on $M$. Because a compact metric space has finite diameter, every unit vector in $T_p M$ has a finite cut time, no greater than the diameter of $M$. Let $\bar{B}_1(0) \subseteq T_p M$ denote the closed unit ball in $T_p M$, and define a map $f : \bar{B}_1(0) \to \operatorname{ID}(p)$ by
\[
f(v) = \begin{cases}
t_{\operatorname{cut}}\left(p, \frac{v}{|v|_g}\right) v, & v \neq 0, \\
0 & v = 0.
\end{cases}
\]

It follows from Theorem 10.33 that $f$ is continuous, and it is easily seen to be bijective, so it is a homeomorphism by the closed map lemma (Lemma A.4). Since every orthonormal basis for $T_pM$ yields a homeomorphism of $\overline{B}_1(0)$ with $\overline{\mathbb{B}}^n$, it follows that $\text{ID}(p)$ is homeomorphic to $\overline{\mathbb{B}}^n$ and the homeomorphism takes $\text{TCL}(p) = \partial \text{ID}(p)$ to $S^{n-1}$.

By Theorem 10.34, $\exp_p$ restricts to a surjective map from $\text{ID}(p)$ to $M$, and it is a quotient map by the closed map lemma. It follows that $M$ is homeomorphic to the quotient of $\text{ID}(p)$ by the equivalence relation $v \sim w$ if and only if $\exp_p(v) = \exp_p(w)$. Since $\exp_p$ is injective on $\text{ID}(p)$ and the images of $\text{ID}(p)$ and $\partial \text{ID}(p) = \text{TCL}(p)$ are disjoint, the equivalence relation identifies only points on the boundary of $\text{ID}(p)$.
\end{proof}

Let $(M,g)$ be a complete, connected Riemannian manifold. For each $p \in M$, the injectivity radius at $p$ is the distance from $p$ to its cut locus if the cut locus is nonempty, and infinite otherwise.

\begin{proof}
Given $p \in M$, let $d$ denote the distance from $p$ to its cut locus, with the convention that $d = \infty$ if the cut locus is empty. Let $a \in (0, \infty)$ be arbitrary, and let $B_a \subseteq T_pM$ denote the set of vectors $v \in T_pM$ with $|v|_g < a$ (so $B_a = T_pM$ if $a = \infty$). We will show that the restriction of $\exp_p$ to $B_a$ is a diffeomorphism onto its image if and only if $a \leq d$, from which the result follows.

First suppose $a \leq d$. By definition of $d$, no point of the form $\exp_p(v)$ with $v \in B_a$ can be a cut point of $p$, so $B_a \subseteq \text{ID}(p)$. It follows from Theorem 10.34(c) that $\exp_p$ is a diffeomorphism from $B_a$ onto its image.

On the other hand, if $a > d$, then $p$ has a cut point $q$ whose distance from $p$ is less than $a$. It follows from the definition of cut points that the radial geodesic from $p$ to $q$ is not minimizing past $q$, so Proposition 6.11 shows that there is no geodesic ball of radius greater than $d_g(p,q)$. In particular, the restriction of $\exp_p$ to $B_a$ cannot be a diffeomorphism onto its image.
\end{proof}

Let $r$, $\partial_r$, and $\mathcal{H}_r$ be defined as above.
\begin{enumerate}[label=\textup{(\alph*)}]
\item $\mathcal{H}_r$ is self-adjoint.
\item $\mathcal{H}_r(\partial_r) \equiv 0$.
\item The restriction of $\mathcal{H}_r$ to vectors tangent to a level set of $r$ is equal to the shape operator of the level set associated with the normal vector field $N = -\partial_r$.
\end{enumerate}

\begin{proof}
Since the covariant Hessian $\nabla^2 r$ is symmetric, equation (11.2) shows that the Hessian operator is self-adjoint. Part (b) follows immediately from the fact that $\mathcal{H}_r(\partial_r) = \nabla_{\partial_r} \partial_r = 0$ because the integral curves of $\partial_r$ are geodesics.

Next, note that $\partial_r$ is a unit vector field normal to each level set of $r$ by the Gauss lemma, so (c) follows from the Weingarten equation 8.11.
\end{proof}

Suppose $(M, g)$ is a Riemannian manifold, $U \subseteq M$ is a normal neighborhood of $p \in M$, and $r$ is the radial distance function on $U$. If $\gamma : [0, b] \to U$ is a unit-speed radial geodesic segment starting at $p$, and $J \in \mathfrak{J}^{\perp}(\gamma)$ is a normal Jacobi field along $\gamma$ that vanishes at $t = 0$, then the following equation holds for all $t \in (0, b]$:
\begin{equation}
D_t J(t) = \mathcal{H}_r(J(t)).
\tag{11.3}
\end{equation}

Suppose $(M, g)$ is a Riemannian manifold, $U \subseteq M$ is a normal neighborhood of $p \in M$, and $r$ is the radial distance function on $U$. Then $g$ has constant sectional curvature $c$ on $U$ if and only if the following formula holds at all points of $U \setminus \{p\}$:
\begin{equation}
\mathcal{H}_r = \frac{s_c'(r)}{s_c(r)}\pi_r, \tag{11.6}
\end{equation}
where $s_c$ is defined by (10.8), and for each $q \in U \setminus \{p\}$, $\pi_r : T_q M \to T_q M$ is the orthogonal projection onto the tangent space of the level set of $r$ (equivalently, onto the orthogonal complement of $\partial_r|_q$).

Let $(M, g)$ be a Riemannian manifold; let $U$ be a normal neighborhood of a point $p \in M$; let $r : U \to \mathbb{R}$ be the radial distance function; and let $\gamma : [0, b] \to U$ be a unit-speed radial geodesic. The Hessian operator $\mathcal{H}_r$ satisfies the following equation along $\gamma|_{[0,b]}$, called a \emph{Riccati equation}:
\begin{equation}
D_t \mathcal{H}_r + \mathcal{H}_r^2 + R_{\gamma'} = 0, \tag{11.7}
\end{equation}
where $\mathcal{H}_r^2$ and $R_{\gamma'}$ are the endomorphism fields along $\gamma$ defined by $\mathcal{H}_r^2(w) = \mathcal{H}_r(\mathcal{H}_r(w))$ and $R_{\gamma'}(w) = R(w,\gamma')\gamma'$, with $R$ the curvature endomorphism of $g$.

Suppose $(M,g)$ is a Riemannian manifold and $\gamma : [a,b] \to M$ is a unit-speed geodesic segment. Suppose $\eta, \bar{\eta}$ are self-adjoint endomorphism fields along $\gamma|_{[a,b]}$ that satisfy the following Riccati equations:
\begin{equation}
D_t \eta + \eta^2 + \sigma = 0, \quad D_t \tilde{\eta} + \tilde{\eta}^2 + \tilde{\sigma} = 0,
\tag{11.8}
\end{equation}
where $\sigma$ and $\tilde{\sigma}$ are continuous self-adjoint endomorphism fields along $\gamma$ satisfying
\begin{equation}
\tilde{\sigma}(t) \ge \sigma(t) \quad \text{for all } t \in [a, b].
\tag{11.9}
\end{equation}

Suppose further that $\lim_{t \searrow a} (\tilde{\eta}(t) - \eta(t))$ exists and satisfies
\[
\lim_{t \searrow a} (\tilde{\eta}(t) - \eta(t)) \le 0.
\]

Then
\[
\tilde{\eta}(t) \le \eta(t) \quad \text{for all } t \in (a, b].
\]

Suppose $H, \tilde{H}: [a,b] \to S(n, \mathbb{R})$ satisfy the following matrix Riccati equations:
\begin{equation}
H' + H^2 + S = 0, \quad \tilde{H}' + \tilde{H}^2 + \tilde{S} = 0,
\tag{11.10}
\end{equation}
where $S, \tilde{S}: [a,b] \to S(n, \mathbb{R})$ are continuous and satisfy
\begin{equation}
\tilde{S}(t) \ge S(t) \quad \text{for all } t \in [a,b].
\tag{11.11}
\end{equation}

Suppose further that $\lim_{t \searrow a} (\tilde{H}(t) - H(t))$ exists and satisfies
\begin{equation}
\lim_{t \searrow a} (\tilde{H}(t) - H(t)) \le 0.
\tag{11.12}
\end{equation}

Then
\begin{equation}
\tilde{H}(t) \le H(t) \quad \text{for all } t \in (a,b].
\tag{11.13}
\end{equation}

Suppose $(M, g)$ is a Riemannian $n$-manifold, $p \in M$, $U$ is a normal neighborhood of $p$, and $r$ is the radial distance function
on $U$.

\begin{enumerate}
\item[(a)] If all sectional curvatures of $M$ are bounded above by a constant $c$, then the
following inequality holds in $U_0 \setminus \{p\}$:
\begin{equation}
\mathcal{H}_r \geq \frac{s'_c(r)}{s_c(r)}\pi_r,
\tag{11.17}
\end{equation}
where $s_c$ and $\pi_r$ are defined as in Proposition 11.3, and $U_0 = U$ if $c \leq 0$,
while $U_0 = \{q \in U : r(q) < \pi R\}$ if $c = 1/R^2 > 0$.

\item[(b)] If all sectional curvatures of $M$ are bounded below by a constant $c$, then the
following inequality holds in all of $U \setminus \{p\}$:
\begin{equation}
\mathcal{H}_r \leq \frac{s'_c(r)}{s_c(r)}\pi_r.
\tag{11.18}
\end{equation}
\end{enumerate}

Suppose $(M,g)$ is a Riemannian $n$-manifold, $p \in M$, $U$ is a normal neighborhood of $p$, $r$ is the radial distance function on $U$, and $s_c$ and $\pi_r$ are defined as in Proposition~11.3.

\begin{enumerate}
\item[(a)] If all sectional curvatures of $M$ are bounded above by a constant $c$, then the principal curvatures of the $r$-level sets in $U_0 \setminus \{p\}$ (with respect to the inward unit normal) satisfy
\begin{equation*}
\kappa \geq \frac{s_c'(r)}{s_c(r)},
\end{equation*}
where $U_0 = U$ if $c \leq 0$, while $U_0 = \{q \in U : r(q) < \pi R\}$ if $c = 1/R^2 > 0$.

\item[(b)] If all sectional curvatures of $M$ are bounded below by a constant $c$, then the principal curvatures of the $r$-level sets in $U \setminus \{p\}$ (with respect to the inward unit normal) satisfy
\begin{equation*}
\kappa \leq \frac{s_c'(r)}{s_c(r)}.
\end{equation*}
\end{enumerate}

Proof. This follows immediately from the fact that the shape operator of each $r$-level set is the restriction of $\mathcal{H}_r$ by Lemma~11.1(c). \qed

Suppose $(M,g)$ is a Riemannian manifold, $\gamma : [0,b] \to M$ is a unit-speed geodesic segment, and $J$ is any normal Jacobi field along $\gamma$ such that $J(0) = 0$. For each $c \in \mathbb{R}$, let $s_c$ be the function defined by~(10.8).

\begin{enumerate}
\item[(a)] If all sectional curvatures of $M$ are bounded above by a constant $c$, then
\begin{equation*}
|J(t)| \geq s_c(t)|D_t J(0)| \tag{11.21}
\end{equation*}
for all $t \in [0, b_1]$, where $b_1 = b$ if $c \leq 0$, and $b_1 = \min(b, \pi R)$ if $c = 1/R^2 > 0$.

\item[(b)] If all sectional curvatures of $M$ are bounded below by a constant $c$, then
\begin{equation*}
|J(t)| \leq s_c(t)|D_t J(0)| \tag{11.22}
\end{equation*}
for all $t \in [0, b_2]$, where $b_2$ is chosen so that $\gamma(b_2)$ is the first conjugate point to $\gamma(0)$ along $\gamma$ if there is one, and otherwise $b_2 = b$.
\end{enumerate}

Let $(M, g)$ be a Riemannian manifold, and let $(U, (x^i))$ be any normal coordinate chart for $g$ centered at $p \in M$. For each $c \in \mathbb{R}$, let $g_c$ denote the constant-curvature metric on $U \setminus \{p\}$ given in the same coordinates by formula (10.17).

\begin{enumerate}
\item[(a)] Suppose all sectional curvatures of $g$ are bounded above by a constant $c$. If $c \leq 0$, then for all $q \in U \setminus \{p\}$ and all $w \in T_q M$, we have $g(w, w) \geq g_c(w, w)$. If $c = 1/R^2 > 0$, then the same holds, provided that $d_g(p, q) < \pi R$.

\item[(b)] If all sectional curvatures of $g$ are bounded below by a constant $c$, then for all $q \in U \setminus \{p\}$ and all $w \in T_q M$, we have $g(w,w) \le g_c(w,w)$.
\end{enumerate}

Let $(M, g)$ be a Riemannian $n$-manifold, and suppose there is a constant $c$ such that the Ricci curvature of $M$ satisfies $\operatorname{Rc}(v, v) \geq (n-1)c$ for all unit vectors $v$. Given any point $p \in M$, let $U$ be a normal neighborhood of $p$ and let $r$ be the radial distance function on $U$. Then the following inequality holds on $U_0 \setminus \{p\}$:
\begin{equation}
\Delta r \le (n-1) \frac{s_c'(r)}{s_c(r)},
\tag{11.27}
\end{equation}
where $s_c$ is defined by (10.8), and $U_0 = U$ if $c \le 0$, while $U_0 = \{q \in U : r(q) < \pi R\}$ if $c = 1/R^2 > 0$.

Let $(M, g)$ be a Riemannian $n$-manifold, and suppose there is a positive constant $c = 1/R^2$ such that the Ricci curvature of $M$ satisfies $\mathrm{Rc}(v,v) \geq (n-1)c$ for all unit vectors $v$. Then every geodesic segment of length at least $\pi R$ has a conjugate point.

\begin{proof}
Let $U$ be a normal neighborhood of an arbitrary point $p \in M$. The second Laplacian comparison theorem (Thm. 11.15) combined with Lemma 11.13 shows that
\[
\partial_r \log(r^{n-1}\sqrt{\det g}) = \Delta r \leq (n-1) \frac{s_c'(r)}{s_c(r)} = \partial_r \log(s_c(r)^{n-1})
\]
on the subset $U_0 \subseteq U$ where $r < \pi R$. Since $r^{n-1}\sqrt{\det g}/s_c(r)^{n-1} \to 1$ as $r \to 0$, this implies that $r^{n-1}\sqrt{\det g}/s_c(r)^{n-1} \leq 1$ everywhere in $U_0$, or equivalently,
\begin{equation}
\sqrt{\det g} \leq s_c(r)^{n-1}/r^{n-1}. \tag{11.31}
\end{equation}

Suppose $U$ contains a point $q$ where $r \geq \pi R$, and let $\gamma : [0,b] \to U$ be the unit-speed radial geodesic from $p$ to $q$. Because $s_c(\pi R) = 0$, (11.31) shows that $\det g(\gamma(t)) \to 0$ as $t \to \pi R$, and therefore by continuity $\det g = 0$ at $\gamma(b)$, which contradicts the fact that $\det g > 0$ in every coordinate neighborhood. The upshot is that no normal neighborhood can include points where $r \geq \pi R$.

Now suppose $\gamma : [0,b] \to M$ is a unit-speed geodesic with $b \geq \pi R$, and assume for the sake of contradiction that $\gamma$ has no conjugate points. Let $p = \gamma(0)$ and $q = \gamma(b)$, so $\gamma(t) = \exp_p(tv_0)$ for $t \in [0, b]$. As in the proof of Theorem 11.9, because $\gamma$ has no conjugate points, we can choose a star-shaped open subset $W \subseteq T_pM$ containing the set $L = \{tv : 0 \leq t < b_0\} \subseteq T_pM$ on which $\exp_p$ is a local diffeomorphism, and let $\bar{g}$ be the pulled-back metric $\exp_p^* g$ on $W$, which satisfies the same curvature estimates as $g$. Then $\bar{\gamma}(t) = tv$ is a radial $\bar{g}$-geodesic in $W$ of length greater than or equal to $\pi R$, which contradicts the argument in the preceding paragraph. \qed
\end{proof}

Let $(M, g)$ be a Riemannian $n$-manifold, and suppose there is a positive constant $c = 1/R^2$ such that the Ricci curvature of $M$ satisfies $\mathrm{Rc}(v,v) \geq (n-1)c$ for all unit vectors $v$. Then for every point $p \in M$, we have $\mathrm{inj}(p) \leq \pi R$.

\begin{proof}
Every radial geodesic segment in a geodesic ball is minimizing, but the preceding theorem shows that no geodesic segment of length $\pi R$ or greater is minimizing. Thus no geodesic ball has radius greater than $\pi R$. \qed
\end{proof}

Let $(M, g)$ be a complete, connected Riemannian $n$-manifold, and suppose there is a positive constant $c = 1/R^2$ such that the Ricci curvature of $M$ satisfies $\mathrm{Rc}(v,v) \geq (n-1)c$ for all unit vectors $v$. Then the diameter of $M$ is less than or equal to $\pi R$.

\begin{proof}
This follows from the fact that any two points of $M$ can be connected by a minimizing geodesic segment, and the conjugate point comparison theorem implies that no such segment can have length greater than $\pi R$. \qed
\end{proof}

With $(M,g)$, $(\tilde{M},\tilde{g})$, and $\varphi$ as above, if $\{(U_t, \varphi_t)\}$ and $\{(U'_t, \varphi'_t)\}$ are two analytic continuations of $\varphi$ along the same path $\gamma: [0,1] \to M$, then $\varphi'_1 = \varphi_1$ on a neighborhood of $\gamma(1)$.

\begin{proof}
Let $\mathcal{T}$ be the set of all $t \in [0, 1]$ such that $\varphi_t = \varphi'_t$ on a neighborhood of $\gamma(t)$. Then $0 \in \mathcal{T}$, because both $\varphi_0$ and $\varphi'_0$ agree with $\varphi$ on a neighborhood of $\gamma(0)$. We will show that $\mathcal{T}$ is open and closed in $[0, 1]$, from which it follows that $1 \in \mathcal{T}$, which proves the lemma.

To see that it is open, suppose $t \in \mathcal{T}$. By the definition of analytic continuation, there is some $\delta > 0$ such that if $t_1 \in [0, 1]$ and $|t_1 - t| < \delta$, then $\varphi_{t_1}$ and $\varphi'_{t_1}$ both agree with $\varphi_t$ on a neighborhood of $\gamma(t)$, so $[0,1] \cap (t - \delta, t + \delta) \subseteq \mathcal{T}$. Thus $\mathcal{T}$ is open.

To see that it is closed, suppose $t$ is a limit point of $\mathcal{T}$. There is a sequence $t_i \to t$ such that $t_i \in \mathcal{T}$, which means that $\varphi_{t_i} = \varphi'_{t_i}$ on a neighborhood of $t_i$ for each $i$. By definition of analytic continuation, for $i$ large enough, we have $\gamma(t_i) \in U_t \cap U'_t$ and $\varphi_t = \varphi_{t_i} = \varphi'_t = \varphi'_i$ on a neighborhood of $\gamma(t_i)$. In particular, this means that $\varphi_t(\gamma(t_i)) = \varphi'_i(\gamma(t_i))$ and $d(\varphi_t)_{\gamma(t_i)} = d(\varphi'_i)_{\gamma(t_i)}$ for each such $i$. By continuity, therefore, $\varphi_t(\gamma(t)) = \varphi'_i(\gamma(t))$ and $d(\varphi_t)_{\gamma(t)} = d(\varphi'_i)_{\gamma(t)}$. Proposition 5.22 shows that $\varphi_t = \varphi'_t$ on a neighborhood of $\gamma(t)$, so $t \in \mathcal{T}$.
\end{proof}

Suppose $(M, g)$ is a complete, connected Riemannian manifold. The following are equivalent:
\begin{enumerate}
\item[(a)] $M$ has parallel curvature tensor;
\item[(b)] $M$ is a locally symmetric space;
\item[(c)] $M$ is isometric to a Riemannian quotient $\tilde{M}/\Gamma$, where $\tilde{M}$ is a (globally) symmetric space and $\Gamma$ is a discrete Lie group that acts freely, properly, and isometrically on $\tilde{M}$.
\end{enumerate}

Suppose $(M,g)$ is a Cartan--Hadamard manifold. Given $q \in M$, let $f : M \to [0,\infty)$ be the function $f(x) = \frac{1}{2}d_g(x,q)^2$. Then $f$ is strictly geodesically convex, in the sense that for every geodesic segment $\gamma : [0,1] \to M$, the following inequality holds for all $t \in (0,1)$:
\begin{equation}
f(\gamma(t)) < (1-t)f(\gamma(0)) + tf(\gamma(1)). \tag{12.1}
\end{equation}

}
}
Every topological manifold with or without boundary is locally path-connected and locally compact.

}
Suppose $M$ and $N$ are topological spaces, and $F : M \to N$ is a continuous map that is either open or closed.
\begin{enumerate}
\item[(a)] If $F$ is surjective, it is a quotient map.
\item[(b)] If $F$ is injective, it is a topological embedding.
\item[(c)] If $F$ is bijective, it is a homeomorphism.
\end{enumerate}

}
Suppose $M$ and $N$ are smooth manifolds of dimensions $m$ and $n$, respectively, and $F: M \to N$ is a smooth map with constant rank $r$. For each $p \in M$ there exist smooth charts $(U, \varphi)$ for $M$ centered at $p$ and $(V, \psi)$ for $N$ centered at $F(p)$ such that $F(U) \subseteq V$, in which $F$ has a coordinate representation of the form
\begin{equation}
\tilde{F}(x^1, \ldots, x^r, x^{r+1}, \ldots, x^m) = (x^1, \ldots, x^r, 0, \ldots, 0). \tag{A.5}
\end{equation}

