}
Let $M$ and $N$ be smooth manifolds and let $\pi: M \to N$ be a smooth submersion.
\begin{enumerate}[label=(\alph*)]
\item $\pi$ is an open map.
\item If $\pi$ is surjective, it is a quotient map.
\end{enumerate}

Let $M$ be a smooth manifold with or without boundary, and suppose that for each $p \in M$ we are given a real vector space $E_p$ of some fixed dimension $k$. Let $E = \bigsqcup_{p \in M} E_p$ (the disjoint union of all the spaces $E_p$), and let $\pi : E \to M$ be the map that takes each element of $E_p$ to the point $p$. Suppose furthermore that we are given
\begin{enumerate}
\item[(i)] an indexed open cover $\{U_\alpha\}_{\alpha \in A}$ of $M$;
\item[(ii)] for each $\alpha \in A$, a bijective map $\Phi_\alpha : \pi^{-1}(U_\alpha) \to U_\alpha \times \mathbb{R}^k$ whose restriction to each $E_p$ is a linear isomorphism from $E_p$ to $\{p\} \times \mathbb{R}^k \cong \mathbb{R}^k$;
\item[(iii)] for each $\alpha, \beta \in A$ such that $U_\alpha \cap U_\beta \neq \emptyset$, a smooth map $\tau_{\alpha\beta} : U_\alpha \cap U_\beta \to \mathrm{GL}(k,\mathbb{R})$ such that the composite map $\Phi_\alpha \circ \Phi_\beta^{-1}$ from $(U_\alpha \cap U_\beta) \times \mathbb{R}^k$ to itself has the form
\begin{equation}
\Phi_\alpha \circ \Phi_\beta^{-1}(p, v) = (p, \tau_{\alpha\beta}(p)v).
\tag{A.6}
\end{equation}
\end{enumerate}

Then $E$ has a unique smooth manifold structure making it a smooth vector bundle of rank $k$ over $M$, with $\pi$ as projection and the maps $\Phi_\alpha$ as smooth local trivializations.

Let $F : M \to N$ be a diffeomorphism between smooth manifolds with or without boundary. For every $X \in \mathfrak{X}(M)$, there is a unique vector field $F_* X \in \mathfrak{X}(N)$, called the \textbf{pushforward of } $X$, that is $F$-related to $X$. For every $f \in C^\infty(N)$, it satisfies
\begin{equation}
((F_* X)f) \circ F = X(f \circ F).
\tag{A.7}
\end{equation}

[LeeSM, Prop. 14.26] If $F: M \to N$ is a smooth map, then for each $k$, the pullback map $F^*: \Omega^k(N) \to \Omega^k(M)$ commutes with $d$: for all $\omega \in \Omega^k(N)$,
\begin{equation}
F^*(d\omega) = d(F^*\omega). \tag{B.12}
\end{equation}

If $M$ is an oriented smooth $n$-manifold with boundary and $\omega$ is a compactly supported smooth $(n-1)$-form on $M$, then
\begin{equation}
\int_M d\omega = \int_{\partial M} \omega. \tag{B.13}
\end{equation}

Suppose $F : G \to H$ is a Lie group homomorphism.
\begin{enumerate}
\item[(a)] $F$ has constant rank.
\item[(b)] The kernel of $F$ is an embedded Lie subgroup of $G$.
\item[(c)] The image of $F$ is an immersed Lie subgroup of $H$.
\end{enumerate}

Let $G$ be a Lie group and let $g$ be its Lie algebra.

\begin{enumerate}
\item[$(a)$] $\exp^G : g \to G$ is smooth.
\item[$(b)$] For every $X \in g$, the map $\gamma : \mathbb{R} \to G$ defined by $\gamma(t) = \exp^G(tX)$ is the one-parameter subgroup generated by $X$.
\item[$(c)$] The differential $(d\exp^G)_o : T_o g \to T_e G$ is the identity map, under the canonical identifications of $T_o g$ and $T_e G$ with $g$.
\end{enumerate}

\begin{enumerate}
\item[(a)] If $G$ is an abelian Lie group, then $C_\varphi$ is the identity map for every $\varphi \in G$, so the adjoint representation is trivial: $\text{Ad}(\varphi) = \text{Id}_\mathfrak{g}$ for all $\varphi \in G$.

\item[(b)] Suppose $G$ is a Lie subgroup of $\text{GL}(n,\mathbb{R})$. Then for each $A \in G$, the conjugation map $C_A(B) = ABA^{-1}$ is the restriction to $G$ of a linear map from the space $\text{M}(n,\mathbb{R})$ of $n \times n$ matrices to itself. Its differential, therefore, is given by the same formula: $\text{Ad}(A)X = AXA^{-1}$ for every $A \in G$ and $X \in \text{Lie}(G) \subseteq \mathfrak{gl}(n,\mathbb{R})$.
\end{enumerate}
